package org.apache.commons.csv;
import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;
import java.lang.reflect.Field;

public class CSVFormatTest {

    @Test
    void testIsEscapeCharacterSet_whenEscapeCharacterIsNull() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;
        // escapeCharacter is private final, use reflection to set it to null
        Field escapeField = CSVFormat.class.getDeclaredField("escapeCharacter");
        escapeField.setAccessible(true);
        escapeField.set(format, null);

        boolean result = format.isEscapeCharacterSet();
        assertFalse(result);
    }

    @Test
    void testIsEscapeCharacterSet_whenEscapeCharacterIsSet() throws Exception {
        // Create a CSVFormat instance with escape character set
        CSVFormat format = CSVFormat.DEFAULT.withEscape('\\');

        boolean result = format.isEscapeCharacterSet();
        assertTrue(result);
    }
}
